using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    #region CalculateTotal — DataRow tests

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(25.00, 2, 0.10, 55.00, DisplayName = "Two items, 10% tax")]
    [DataRow(99.99, 3, 0.08, 323.97, DisplayName = "Three items, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(50.00, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, Math.Round(result, 2));
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below zero")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above one")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    #endregion

    #region ApplyDiscount — DynamicData with ValueTuples

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> ApplyDiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (0m, 50m, 0m),
        (149.99m, 20m, 119.992m),
    ];

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountInvalidTestData))]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(
        decimal price, decimal discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));
    }

    public static IEnumerable<(decimal price, decimal discountPercent)> ApplyDiscountInvalidTestData =>
    [
        (100m, -1m),
        (100m, 101m),
        (50m, -0.01m),
        (50m, 100.01m),
    ];

    #endregion

    #region FormatPrice — DataRow tests

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default currency")]
    [DataRow(1000.50, "€", "€1000.50", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(5.1, "£", "£5.10", DisplayName = "Rounds to 2 decimals")]
    public void FormatPrice_ReturnsFormattedString(
        double price, string currencySymbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, currencySymbol);

        Assert.AreEqual(expected, result);
    }

    #endregion
}

